export type Cell = [number, number];

const isNeighbor = ([x1, y1]: Cell, [x2, y2]: Cell): boolean =>
  (x1 !== x2 || y1 !== y2) &&
  Math.abs(x1 - x2) <= 1 &&
  Math.abs(y1 - y2) <= 1;

const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
  liveCells.filter((other) => isNeighbor(cell, other)).length;

const cellKey = ([x, y]: Cell): string => `${x},${y}`;

const neighborsOf = ([x, y]: Cell): Cell[] => {
  const result: Cell[] = [];
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx !== 0 || dy !== 0) {
        result.push([x + dx, y + dy]);
      }
    }
  }
  return result;
};

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set(cells.map(cellKey));
  const survivors = cells.filter((cell) => {
    const liveNeighborCount = countLiveNeighbors(cell, cells);
    return liveNeighborCount === 2 || liveNeighborCount === 3;
  });

  const candidateDeadCells = new Map<string, Cell>();
  for (const cell of cells) {
    for (const n of neighborsOf(cell)) {
      const key = cellKey(n);
      if (!liveSet.has(key)) {
        candidateDeadCells.set(key, n);
      }
    }
  }

  const born: Cell[] = [];
  for (const deadCell of candidateDeadCells.values()) {
    if (countLiveNeighbors(deadCell, cells) === 3) {
      born.push(deadCell);
    }
  }

  return [...survivors, ...born];
}

